import boto3
import json
from typing import Dict, Any

def lambda_handler(event: Dict[str, Any], context: Any) -> Dict[str, Any]:
    # Initialize SNS client
    sns_client = boto3.client('sns')
    
    # Extract message and topic ARN from event
    message = event.get('message')
    topic_arn = event.get('topic_arn')
    message_type = event.get('message_type', 'default')
    
    # Validate inputs
    if not message or not topic_arn:
        return {
            'statusCode': 400,
            'body': json.dumps('Message and topic_arn are required')
        }
    
    try:
        # Publish message based on message type
        if message_type == 'alert':
            response = sns_client.publish(
                TopicArn=topic_arn,
                Message=json.dumps({
                    'type': 'alert',
                    'timestamp': context.aws_request_id,
                    'message': message
                }),
                Subject='Alert Notification'
            )
        elif message_type == 'info':
            response = sns_client.publish(
                TopicArn=topic_arn,
                Message=json.dumps({
                    'type': 'info',
                    'timestamp': context.aws_request_id,
                    'message': message
                }),
                Subject='Information Notification'
            )
        else:
            response = sns_client.publish(
                TopicArn=topic_arn,
                Message=message,
                Subject='Default Notification'
            )
        
        return {
            'statusCode': 200,
            'body': json.dumps({
                'message': 'Message published successfully',
                'message_id': response['MessageId']
            })
        }
        
    except Exception as e:
        return {
            'statusCode': 500,
            'body': json.dumps(f'Error publishing message: {str(e)}')
        }